<!DOCTYPE html><html lang="id"><head><meta charset="UTF-8"><title>Cetak Laporan Transaksi</title><style>body{font-family:Arial,sans-serif;font-size:12px}table{width:100%;border-collapse:collapse}th,td{border:1px solid #333;padding:8px}th{background:#eee}.right{text-align:right}.center{text-align:center}@media print{button{display:none}}</style></head><body onload="window.print()"><h2 class="center">Laporan Transaksi Jayusman Market</h2><p>Periode: {{ request('start_date') ?? '-' }} s/d {{ request('end_date') ?? '-' }}</p><table><thead><tr><th>Invoice</th><th>Cabang</th><th>Kasir</th><th>Total</th><th>Tanggal</th></tr></thead><tbody>@php $grandTotal=0; @endphp @foreach($transactions as $transaction) @php $grandTotal += $transaction->total_price; @endphp<tr><td>{{ $transaction->invoice_number }}</td><td>{{ $transaction->branch->name ?? '-' }}</td><td>{{ $transaction->cashier->name ?? '-' }}</td><td class="right">Rp {{ number_format($transaction->total_price,0,',','.') }}</td><td>{{ $transaction->transaction_date }}</td></tr>@endforeach<tr><th colspan="3" class="right">Total Pendapatan</th><th class="right">Rp {{ number_format($grandTotal,0,',','.') }}</th><th></th></tr></tbody></table><br><button onclick="window.print()">Cetak</button></body></html>
